INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (1, "プリンセスなプリンなの\nお店にあったいろんな食べもの\nを入れられるだけ入れてみたの\nどんな味なのか楽しみなの", 1, 100, "おいしすぎて食べ始めたら\n止まらない最高のプリンなの\n今のミヤコを止められるヤツは\n誰もいないの", 5, "ペコリーヌのプリン", "やばいですね☆なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (2, "いつもオマエのそばに寄りそう\nヤツのぷりんなの。ミヤコの\nワガママもやさしく受け入れて\nくれそうなの", 1, 101, "なんだかすごくやさしい気持ち\nになる味なの…\nおはようからおやすみまで\nずっと一緒な味なの…", 5, "コッコロのプリン", "主さま、なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (3, "ツンツンデレデレなヤツの\nプリンなの。砂糖とスパイスを\n混ぜてみたの。どんな味になる\nか楽しみなの", 0, 102, "いろんな味が一度で楽しめる\nプリンなの。ツンデレはプリン\nにするとおいしいの。ミヤコも\nツンデレを目指してみるの", 5, "キャルのプリン", "ぶっ殺すぞ！なの！\n…デレデレはどこなの？", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (4, "オマエと同じで、一度赤ちゃん\nみたいになったヤツのプリン\nなの。ヒンヤリ、プリンアイス\nにしてみたの", 1, 103, "あったかいところで食べる\nプリンアイスは最高なの～♪\n安心しすぎて昔の記憶のない\nミヤコも心が子どもになるの～", 5, "シェフィのプリン", "おにーたん♪なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (5, "イリヤを見てたら思いついた\nトマトジュースが隠し味の\nプリンなの。栄養満点なの", 1, 104, "トマトで栄養補給も完璧なの\nどんどん力がみなぎってきて\n復活も夢じゃないの\nミヤコが復活したら…", 5, "イリヤのプリン", "ハーハッハッハ！\n世界征服なのじゃなのー！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (6, "アカリのプリンなの。ヨリと\n同じくらいかわいく作って\nやったの。正直ミヤコは\nおいしければなんでもいいの", 1, 105, "見た目がかわいくてもミヤコは\n味にも厳しいの。あむっ…\nこ、これは…！なんだかすごく\n変な気分になってきたの…", 5, "アカリのプリン", "お兄ちゃんのエッチ！　なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (7, "かわいくつくらないとアカリが\n怒りそうだからヨリのプリンは\nかわいく作ったの。自信作なの", 1, 106, "んむぅ…これはなかなか感想が\n難しいプリンなの…率直に言い\nたいような…心のうちに秘めて\nおきたいような…", 5, "ヨリのプリン", "えっと…その…あんたのこと…\nだ、大っ嫌いなのーー！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (8, "シノブはいつもミヤコに\nやさしくしてくれるから\n丁寧に作ったの。ドクロ親父は\nいらないから作ってないの", 0, 107, "このプリンを食べるとシノブが\nミヤコの中にいるみたいなの！\nシノブの力があれば未来の\nプリンを見放題なの！", 5, "シノブのプリン", "お父さん…\nいいかげんにしてなの！\nん？プリンの未来は…\n見えなかったの…", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (9, "黒い鎧を脱がないヤツのプリン\nなの。固めのプリンを目指したら\nカチカチになりすぎたの", 1, 108, "固すぎてかじれないから丸吞み\nにしたの。なんだか体が硬く\nなった気がするの。みんなを\n守れる気がするの！", 5, "ジュンのプリン", "インフェルノシールド！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (10, "オマエをいっつもからかってる\nヤツのプリンなの\nちょっぴり変わったスパイスで\nからかいを表現したの", 1, 109, "口の中でスパイスがプチプチ\nはじけて新食感なの！\nプチプチがミヤコを\n翻弄するの！", 5, "トモのプリン", "あなたといると調子が狂うな\n…なの\n翻弄してたのはオマエなの？", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (11, "王宮騎士団にいるちっこいヤツ\nなの。ちっこいけどやるヤツ\nらしいから、濃いめの味付けに\nしてみたの", 1, 110, "ん～見かけによらず濃厚な\nパンチのある味わいが\n口いっぱいに広がるの！", 5, "マツリのプリン", "タイガーヒーローボンバー！\nなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (13, "なんかすごくクールなプリンなの\nなんかテンションも少し\n低そうなの。これ\n食べちゃっても大丈夫なの？", 1, 111, "クールな見た目なのにとっても\n優しい味なの！なんだか\n懐かしさを感じるの…", 5, "クロエのプリン", "ま、いいんじゃん？\nしらんけどなの", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (14, "きれいにデコれたの！\nカラフルでおいしそうなの\nこれは期待できそうなの", 1, 112, "なんか変わった食感なの…\nちゃる…ちょる…ちぇる？\nちぇるってしてるの\nでもちぇるってなんなの？", 5, "チエルのプリン", "ぷりーん★なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (15, "見た目は完ぺきなの！\nこれをつくったやつは\nきっと天才なの！\n早く食べたいの！", 1, 113, "味はなんか妙に\n甘酸っぱいの…\n食べたことない味なの\nこの味ってもしかして…", 5, "ユニのプリン", "端的に換言すれば\n青春の味なの？", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (16, "オマエから聞いた懐かしい\n味ってヤツを全部入れてみたの\nオマエ記憶がないのに懐かしい\nってどういうことなの？", 1, 114, "ミヤコも幽霊になる前の記憶\nがないのに、なんだか懐かしい\n気持ちになってくるの…", 5, "サレンのプリン", "幼なじみはあんた…なの？", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (17, "たまたま会ったメイドに教えて\nもらった作り方なの。メイドは\nプリンも作れるはずなの。\nなのにこの不安は何なの…？", 1, 115, "おかしいの。このプリンを\n食べてから、３回も転んだの\nミヤコは幽霊だから転んだり\nしないの。なんでなの…？", 5, "スズメのプリン", "ひゃああんなの～！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (18, "怖がりな子どもが教えてくれた\n小さくてかわいいプリンなの　\n触ってないのにぷるぷる震える\n驚きのやわらかさなの", 0, 116, "甘さのなかに少しのしょっぱさ\nクセになる味なの\nこのプリンはがんばればきっと\nいろんな美味しいになれるの", 5, "クルミのプリン", "サルキデバレヤ！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (19, "くまのぬいぐるみを見ていたら\nひらめいたの。小さいけど\nしっかりした甘さの元気に\nなれるプリンなの！", 1, 117, "このプリン、食べるとなんだか\nお姉ちゃんになった気分に\nなるの。ピンチのプリンは\nミヤコが守ってやるの！", 5, "アヤネのプリン", "プリンフルスイングなの～！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (20, "マホマホ王国って国にいる\nお姫様のプリンなの\n魔物も虜にしちゃう\nすてきなプリンなの", 1, 118, "メルヘンパワーがあふれてきて\nいまならミヤコにも魔法が\n使える気がするの！\nほな、いきまひょ～なの！", 5, "マホのプリン", "みらくるみやりん\nくるりんぱ～☆なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (21, "カッコいいプリンを目指して\nワイルドなものをガンガン\n入れてみたの。きっと熱い\nプリンができるはずなの", 1, 119, "うおーん！ミヤコなんだか\n強くなった気がするの！\n困ったことがあればミヤコが\nまとめて面倒見てやるの！", 5, "マコトのプリン", "ウルフェンバイトなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (22, "どっかの国でよくとれる\nゴーヤーに似てるやつを\nいれてみたの！ちょっと\n苦いらしいけど…", 1, 120, "一口食べたら元気が\nあふれて止まらないの！\n気分がいいから、一曲\n踊りでも披露してやるの！", 5, "カオリのプリン", "なんくるないさ～！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (23, "勘の鋭いやつが好きな食べ物を\nたくさん入れてみたの\n難しいこと考えるのにぴったり\nらしいけど、なんでなの？", 1, 121, "むむむ…なるほどなの\n上質な糖分をふんだんに\n使うことで、脳をより活性化\nできるからなの！", 5, "カスミのプリン", "ふふん。簡単な推理なの", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (24, "搾りたての牛乳を\nたっぷり使ったプリンなの～\nマヒルに手伝ってもらって\nミヤコ直々に搾ってきたの！", 1, 122, "ミルクがとっても濃厚で\nほっぺたが落ちちゃうの～♪\nこのプリンからは牧場の…\n自然の息吹を感じるの！", 5, "マヒルのプリン", "エリザベス～！なの～！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (25, "マヒルからやさしいヤツだって\n聞いたの。やさしさを表現\nするために奥ゆかしい甘さに\n仕上げてみたの", 1, 123, "ほのかな甘さでありながら\nしっかりとした主張も\n感じさせる\n味わい深いプリンなの", 5, "シオリのプリン", "私の好きな本…読んで\nもらえたらうれしいです…\nなの", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (26, "牧場にいるヤツらしいの\n牛とは違うらしいの\nもふもふ気持ちいいらしいから\n食感にこだわって作ったの", 1, 124, "こ、これは…！口の中に入れた\n瞬間にふんわり溶けて\nなくなっちゃうの！\nその食感がやみつきなの！", 5, "リマのプリン", "もふもふにしてあげるなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (27, "いっつも寝てるやつらしいの\nぐっすり眠れる薬草をたくさん\n入れてみたの。プリンとして\nおいしくなるかはわからないの", 0, 125, "んむぅ…評価が難しい味なの…\nおいしいのはおいしいの…\nん～考えてたら…\n眠くなってきたの…", 5, "リンのプリン", "めんどくさいな～なの…", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (28, "クレープ屋の真っ赤な人に\n教わったプリンなの\n作り方を丁寧に教えてくれて\nとっても優しい人だったの！", 1, 126, "プ…プリンなのにクレープの味\nがするの。味もすごく普通なの\nでも…なんだかプリンの新しい\n扉を開けそうな気がするの…！", 5, "ラビリスタのプリン", "プリンの権能を解放するの～！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (29, "お店に落ちてた謎のレシピの\nプリンなの。レシピの表紙には\n『お姉ちゃんの愛情たっぷり』\nって書いてあったの", 0, 127, "とろける食感が絶品なの～♪\n食べるとなんだか幸せな\n気持ちになれるの…これが\n愛情ってやつなの？", 5, "シズルのプリン", "お姉ちゃんパワー全開！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (30, "リノから作り方を教わったの！\nさすがクレープ屋で働いてる\nだけあって美味しそうなの！", 1, 128, "これで妹力？があがるらしいの。\n妹になればお兄ちゃんに\nプリンをたかり放題なの！\n最高なの～！", 5, "リノのプリン", "お兄ちゃん、プリンをよこすの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (31, "プリンのレシピで悩んでたら\n通りすがりのおねーさんが\n一緒に考えてくれたプリンなの\nいいヤツもたまにはいるの～♪", 1, 129, "食べたら元気が湧いてくるの\nだからプリンのレシピのお礼に\nミヤコも人助けを手伝って\nやったの。ミヤコはえらいの！", 5, "ヒヨリのプリン", "困った時はお互いさまさま！\nなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (32, "ミヤコががんばって作った\nこだわりのプリンなの～\nプリンは癒しなの。だから優しい\n気持ちで丁寧に作ったの", 1, 130, "はっ…思わずお花畑が見えたの\n身も心も包まれるような\nとっても優しい味がするの\nこれは…まさに癒しなの～♪", 5, "ユイのプリン", "フラワリングヒールなの～♪", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (33, "究極のプリンを作るため\nミヤコは厳しい修行をしたの…\nその結果あって完成した\nクールで完璧なプリンなの！", 1, 131, "確かに完璧なプリンなの\nでも究極のプリンと呼ぶには\nまだまだ修行が必要なの…\nプリン作りは奥が深いの…！", 5, "レイのプリン", "スラッシュテンペスト！なの。", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (34, "豪華で高級な\nお嬢様プリンなの\n中には宝石みたいな\n大きいイチゴを入れるの！", 1, 132, "味にも素材にもこだわりが\nあるの。一流は妥協しないの\nもっと豪華に、もっとおいしく\nできるはず…", 5, "アキノのプリン", "おーほっほほほ！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (35, "外はしっかり、中はふわとろの\nプリンにするの\n泡みたいなしゅわしゅわの\n生クリームも入れるの♪", 1, 133, "プリンは飲み物とも言うの\nぐいっていってみるの\n…ふわしゅわでとろけるの～！\n体に染みわたるの～", 5, "ユカリのプリン", "プリしゅわ最高～！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (36, "餡子を入れて\nオーブンでこんがり焼くの\nたい…焼きプリンなの\n斬新なの！", 1, 134, "このプリンは焼きたてのうちに\n食べるのが一番なの…！\n熱いけどおいしくて\nうずうずしてきたの…！", 5, "タマキのプリン", "にゃにゃにゃ！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (37, "栄養バランスを考えて\n木の実をたくさん入れるの\nあれこれ忙しいときでも\n頼りになるプリンなの！", 0, 135, "プリンはいつでも手軽に\n食べられるのも魅力なの\nこれは食べ応えもあるから一つ\n食べればいっぱい動けるの", 5, "ミフユのプリン", "効率全開！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (38, "エルフの森で子どもにもらった\n薬草を使って作ったの\nこんな優しい味のプリンは\n初めてなの…", 1, 136, "このプリンを食べてから\nいい子になった気がするの\n大好きなプリンを泣いてる子に\nあげたの。いい気分なの", 5, "ミサトのプリン", "あらあら～なの～♪", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (39, "お昼寝でみた夢の中に\nでてきた不思議なプリンを\n作ってみたの。見てたらまた\n眠くなってきたの…", 1, 137, "あまいプリンが口の中で\nぽんぽん弾ける未知の味なの！\n今なら不思議な力で世界も\n救えそうなの！でも眠くなるの…", 5, "ハツネのプリン", "スヤスヤ～…なの…", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (40, "お店のはしっこに一つだけ\n残ったおもちゃを見て思い\nついたの。他のプリンと一緒に\n置いておくと震えだすの", 1, 138, "知らないうちにはしっこに\n隠れちゃってたの。食べたら\nミヤコ、シノブたちに会いに\nいきたくなってきたの", 5, "アオイのプリン", "ぼっちは卒業なの～！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (41, "トップオブアイドルの\nプリンなの。キラキラした\nものを入れて、あつ～い\nオーブンで焼いてみたの", 1, 139, "口の中に華やかな甘さが\n広がる…これがアイドルなの？\n急に歌って踊りたく\nなってきたの！", 5, "ノゾミのプリン", "リズムあげるのー！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (42, "ミヤコにプリンをくれるすごく\nいいヤツのプリンなの\n精霊に呼びかけながら\n一生懸命かき混ぜたの", 1, 140, "プリンの生地がとっても\nなめらかで最高の舌触りなの！\n精霊、ミヤコのプリンのために…", 5, "チカのプリン", "風の加護を！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (43, "歌って踊って衣装も作れるヤツ\nのプリンなの。このプリンは\nきれいに包装するの。プリンを\n最高の形で着飾らせるの", 1, 141, "包装は食べるまでの手間が\n増えてめんどくさいの。でも\nそのめんどくささもプリンの\n味を引き立てるの", 5, "ツムギのプリン", "騎士さんのために\nしたんじゃありません！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (12, "プリンをくれないならどうでも\nいいヤツなの。でも横で\nいろいろ言ってきたから\nがんばって作ったの", 0, 142, "んむっ！？\nく、口のなかでプリンの\nおいしさが大暴れなの！\n止まらないの！", 5, "クリスティーナのプリン", "宴の始まりなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (44, "大人な甘さ控えめのプリンを\n作るの。試しにお魚を入れて\nみるの。プリンの可能性は\n無限大なの！", 1, 143, "大人の味なの。今やミヤコは\nみんなの頼れる姐御なの！\n悪さするやつはミヤコが\n許さないの！", 5, "ルカのプリン", "一刀両断、覚悟しな！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (45, "サイカワサイツヨな\n魔法のプリンなの\n中身をカラフルにするの～\n甘いプリンは頭が冴えるの！", 1, 144, "一口食べる度に味が変わって\n魔法みたいなの！\nもしかして全部食べたら\nミヤコも魔法少女になれるの？", 5, "ナナカのプリン", "きゅぴーん！キタコレ！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (46, "小難しい言葉をささやきながら\n作ったら魔力あふれるプリンが\n爆誕したの！でも、不思議と\nイタイタしいのはなぜなの～？", 1, 145, "一口食べたら謎の組織に\n狙われたり、前世の記憶が蘇る\n気がするの～設定盛りすぎなの\nミヤコは、ミヤコは…", 5, "アンナのプリン", "人呼んで、疾風のミヤコなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (47, "甘酸っぱい赤い木の実を\n切り刻んで入れるの\n甘くてちょっぴり刺激的な\nヤンデレのプリンなの", 1, 146, "なんか普通のプリンよりも\nいい匂いがするの～…\nプリンのことがもっともっと\n好きになっちゃうの…", 5, "エリコのプリン", "クスクス…クスクスクス…なの", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (48, "健康に気を遣うミヤコは\nプリンにお薬を入れてみたの～\nでもなんだか毒々しいから\n彩りにバラを添えてみたの～", 1, 147, "鼻に抜ける薬のにおいがアレ\nだけど大人っぽくて頭が\nよくなった気がするの。無性に\n実験したくてしかたないの", 5, "ミツキのプリン", "どんなプリンも\nミヤコの隻眼からは\n逃れられないの～！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (49, "小さいけどしっかりした\n軍人のプリンなの\nちょっと固めにして\n砂糖はいっぱい入れるの", 1, 148, "ん～王道なプリンは\n甘くて安定したおいしさなの～\n思わず笑顔になっちゃうの\nにこにこなの～♪…はっ！", 5, "モニカのプリン", "私は子どもではない！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (50, "オーエド町で手に入れた素材と\nトーゴクに伝わる術をかけて\nプリンを作るの。シュババ！\n忍法隠し味の術なの！", 1, 149, "このプリンを食べてから\n誰かにお仕えしなきゃ\nいけない気がするデースなの\nそれはショ、ショー…", 5, "ニノンのプリン", "ショーグン！　ミヤコと一緒に\n天下統一するデースなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (51, "オマエが持ってきた手錠を\nヒントに作ったプリンなの\nプリンが動けないように\nカチカチに固めたの", 0, 150, "カチカチに固めたせいで食感が\nプリンのようで\nプリンじゃないの…でもこの\nもどかしさが癖になるの…", 5, "クウカのプリン", "…ぐふふ、じゅるり～なの", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (52, "とっても美しいプリンなの\n美しいものを手当たり次第\n入れたらすごいことになったの", 1, 151, "味も美しい以外の感想が\n出てこないの。ていうかこれを\n食べたミヤコも美しいの！\n鏡、鏡はどこなの！", 5, "ユキのプリン", "あぁ、ミヤコはなんて美しいの～", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (53, "知らないうちにお菓子が売れた\n時に思いついたプリンなの。\n作り方もよく覚えてない…\nけど、きっとおいしいの！", 0, 152, "うん、やっぱりおいしく…\nん？あそこにいるのは\nアイツなの。あれ？\n体が勝手にアイツの方に…", 5, "アユミのプリン", "ジー…ってミヤコなにしてるの\nミヤコはストーカーじゃないの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (54, "イタズラ好きの手下と一緒に\n作ったプリンなの。見た目は\nかわいいけど、作り方は\n意外と複雑なの～", 0, 153, "見た目通り甘々で優しい味なの\nでも、レシピを見たら裏面に\n別の作り方が書いてあるの。\nこれだと激辛プリンに…", 5, "ミソギのプリン", "にひひ…イタズラの時間なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (55, "素直でやさしい手下と一緒に\n動物のぬいぐるみをいっぱい\n並べて作ったの", 0, 154, "ん～、ふわふわの甘々なの！\nなんだか楽しくなって\n心も体もるんたったしてくるの", 5, "ミミのプリン", "ぴょんぴょこぴょーん、なの♪", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (56, "幽霊を怖がっている手下と\n一緒に作ったプリンなの。\n小さいクセにきっちりしてて\nとってもかわいいプリンなの", 0, 155, "ひんやりしてて暑い日でも\nおいしく食べられそうなの！\nん？これを買いたい大人が\nいる？それって…", 5, "キョウカのプリン", "へんたいふしんしゃさんなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (57, "カリスマモデルなプリンなの\nモリモリにデコレーションして\nカリスマ感を演出したの", 1, 156, "見て食べて楽しめる新機軸の\nプリンなの。ミヤコは幽霊\nだけど自分の足でランウェイを\n歩きたくなってきたの！", 5, "スズナのプリン", "ハート狙い撃ち！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (58, "学校の先生をしてるヤツの\nプリンなの。お堅くしようと\nしたら、いつの間にか色っぽく\nなっちゃったの。なんでなの？", 0, 157, "プ、プリンは全部ミヤコのもの\nなのに、なんだかこのプリンは\nいろんな人に教えたく\nなっちゃう不思議な味なの！", 5, "イオのプリン", "授業を始めます♪なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (59, "少し背伸びしたおませな子を\n表現したプリンなの。あえて\n甘さ控えめなの。カラメルは\n後乗せできるから安心するの", 1, 158, "ミヤコはプリンならどんなもの\nでも食べるの。でもカラメルを\nちょっとだけ足すの。\nちょっとだけなら…", 5, "ミサキのプリン", "立派なレディ、なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (60, "謎に包まれたプリンができたの\n何か隠してるようなの…\nこれは危険なプリンなの！", 1, 159, "味はすごいゴージャスなの！\nボスの風格があるの！\nビッグなミヤコに\nプリンを捧げるの！", 5, "ホマレのプリン", "プリンを持ってこないと\nお仕置きだよ～☆なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (61, "ワイルドな見た目なの！\nこれは期待できそうなの。\nきっと躍動感あふれる味なの！", 1, 160, "最初の一口目が\nすごいインパクトなの！\n無性にケンカしたくなるの！\nプリンをよこせなの！", 5, "カヤのプリン", "たぎってきたの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (62, "なんか見た目がパッとしないの\nこれほんとに大丈夫なの？\nなんか頼りないの…", 0, 161, "見た目はアレだけど味はおいし\nいの…あと主張もはっきりして\nるの！やる気と自信だけは\n出てきたのうおおおーなの！", 5, "イノリのプリン", "下剋上、やってやるですなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (63, "天下の大悪党のプリンなの\nこれまでのジョーシキに\n捉われないプリンを\n作ってみたの～", 1, 162, "むむむ…食べたら\nやる気が湧いてきたの！\nミヤコを邪魔するやつはみんな\nまとめてぶっ飛ばしてやるの～", 5, "ムイミのプリン", "どけどけ～！なの～！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (64, "いろんなものに変身したり\n分身したりできるヤツの\nプリンなの。型で同じプリンを\nたくさんたくさん作ったの", 1, 163, "いつのまにか作ったの全部\n食べちゃったの。なんで\nプリンは分身しないの？\n無限に増えろなの！", 5, "ネネカのプリン", "ミラーミラー！なの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (65, "金の亡者のプリンなの\n金にものを言わせて作って\nみたの。おばあちゃんの\nプリンと対極なの", 1, 164, "むぅ…認めたくないけど\nおいしいの…これを何個も\n作れるほどのお金を稼ぐのは\n大変なの…でもおいしいから…", 5, "クレジッタのプリン", "プリンに忠誠を誓いますわ！\nなの！", 3);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES (66, "みんなお世話になるギルド\n管理協会職員のプリンなの\nお役所感を出すために手堅く\n王道に作ったの", 1, 165, "手堅い…！手堅いの…！\n隙のないプリンなの！\n今のミヤコなら完璧な\n書類作成ができそうなの！", 5, "カリンのプリン", "ギルド管理協会へようこそ！\nなの！", 3);
